func (c RuleConfig) Validate() error {
    switch c.Type {
    case EventTypeBalanceThreshold:
        if c.BalanceThreshold == nil {
            return models.NewGenericValidationError(errors.New("missing balance threshold rule config"))
        }
        return c.BalanceThreshold.Validate()
    case EventTypeInvoiceCreated, EventTypeInvoiceUpdated:
        if c.Invoice == nil {
            return models.NewGenericValidationError(errors.New("missing invoice rule config"))
        }
        return c.Invoice.Validate()
    default:
        return models.NewGenericValidationError(fmt.Errorf("unknown rule type: %s", c.Type))
    }
}

func NewSink(config SinkConfig) (*Sink, error) {
    if err := config.Validate(); err != nil {
        return nil, fmt.Errorf("invalid sink configuration: %w", err)
    }
    messageCounter, err := config.MetricMeter.Int64Counter("sink.kafka.messages", metric.WithUnit("{message}"))
    if err != nil {
        return nil, fmt.Errorf("failed to create messages counter: %w", err)
    }
    meterCache, err := NewNamespaceStore(NamespacedMeterCacheConfig{
        PeriodicRefetchInterval: config.MeterRefetchInterval,
        Logger:                  config.Logger,
        MeterService:            config.MeterService,
    })
    if err != nil {
        return nil, fmt.Errorf("failed to create namespace meter cache: %w", err)
    }
    return &Sink{config: config, buffer: NewSinkBuffer(), meterCache: meterCache, ...}, nil
}
